SELECT partner_name, type
FROM partners
ORDER BY partner_name;

SELECT trial_id, COUNT(iti_id) AS total_iti_values
FROM iti_values
GROUP BY trial_id;

SELECT iti_value
FROM iti_values
WHERE trial_id = 0;

SELECT trial_id, iti_value
FROM iti_values
ORDER BY iti_value DESC;

SELECT type, COUNT(*) as partner_count
FROM partners
GROUP BY type;
